def create_point(x, y):
    """Return a tuple representing a 2D point (x, y)."""
    return (x, y)


def create_rgb(r, g, b):
    """Return a tuple representing an RGB color (r, g, b)."""
    return (r, g, b)


def create_single(value):
    """Return a single-element tuple containing value."""
    return (value,)


def create_from_list(lst):
    """Convert a list into a tuple and return it."""
    return tuple(lst)
